issuesFound.explanation:
** The button is shown/hidden by adding/removing the `visible` class, but its `aria‑hidden` state is never updated, so screen readers may still perceive it when it is visually hidden.  
**Fix:**  
```javascript
// Line 1198 – inside _update()
function _update() {
  const shouldShow = window.scrollY > SHOW_AFTER;
  if (shouldShow && !_visible) {
    _visible = true;
    _btn.removeAttribute('hidden');
    _btn.removeAttribute('aria-hidden');          // ← add
    requestAnimationFrame(() => addClass(_btn, CSS.visible));
  } else if (!shouldShow && _visible) {
    _visible = false;
    removeClass(_btn, CSS.visible);
    _btn.setAttribute('aria-hidden', 'true');     // ← add
    setTimeout(() => {
      if (!_visible && _btn) {
        _btn.setAttribute('hidden', '');
      }
    }, delay);
  }
}
```  

